/**
 * Test Data Loader for Performance Profiling
 *
 * Loads deterministic email samples from the database for reproducible performance testing.
 * Separates classification performance measurement from Gmail API latency.
 */

import { Pool } from 'pg';

/**
 * Deterministic test email samples categorized by complexity.
 * These IDs are fixed and represent real Gmail data from the database.
 */
export const TEST_SAMPLES = {
  /** Short emails (< 500 chars) - Expected: rule-based path, < 100ms */
  short: [
    '19928d6e49543f03', // hawaiian shirt (1 char)
    '19923533a9049beb', // todos (42 chars)
    '199d3e4371fc8b53', // stuff to talk about (139 chars)
  ],

  /** Medium emails (500-2000 chars) - Expected: rule-based path, < 500ms */
  medium: [
    '1988896ac502a7f4', // direct deposit (1465 chars)
    '19892a6cf91ee002', // tracked flight (1482 chars)
    '19906810d60cd26d', // crypto portfolio (1301 chars)
  ],

  /** Long emails (> 2000 chars) - Expected: mixed paths, < 1s rule-based, < 10s AI */
  long: [
    '1997666491effefc', // lab results (2908 chars)
    '1987f215352815b2', // github ceo claude (9987 chars)
    '1990fc8fe96cb6bb', // openai anthropic mistral (10542 chars)
  ],
} as const;

/**
 * Database configuration from environment variables.
 */
function getDbConfig() {
  return {
    host: process.env.POSTGRES_HOST || 'localhost',
    port: parseInt(process.env.POSTGRES_PORT || '5432', 10),
    database: process.env.PROJECT_DB_NAME || 'gmail_automation',
    user: process.env.PROJECT_DB_USER || 'gmail_app_user',
    password: process.env.PROJECT_DB_PASS,
  };
}

/**
 * Gmail message structure from database.
 */
export interface GmailMessage {
  gmail_id: string;
  gmail_thread_id: string;
  subject: string | null;
  sent_at: Date | null;
  from_addrs: any;
  from_simple: any;
  to_addrs: any;
  reply_to_addrs: any | null;
  headers: any;
  body_content: string | null;
  body_html: string | null;
  body_text: string | null;
  body_text_as_html: string | null;
  label_ids: string[];
  size_estimate: number | null;
}

/**
 * Load a single email from the database by gmail_id.
 */
export async function loadEmail(pool: Pool, gmailId: string): Promise<GmailMessage> {
  const result = await pool.query(
    `SELECT
      gmail_id,
      gmail_thread_id,
      subject,
      sent_at,
      from_addrs,
      from_simple,
      to_addrs,
      reply_to_addrs,
      headers,
      body_content,
      body_html,
      body_text,
      body_text_as_html,
      label_ids,
      size_estimate
    FROM email.gmail_message
    WHERE gmail_id = $1`,
    [gmailId]
  );

  if (result.rows.length === 0) {
    throw new Error(`Email not found: ${gmailId}`);
  }

  return result.rows[0];
}

/**
 * Load multiple emails from the database by gmail_ids.
 */
export async function loadEmails(pool: Pool, gmailIds: readonly string[]): Promise<GmailMessage[]> {
  const result = await pool.query(
    `SELECT
      gmail_id,
      gmail_thread_id,
      subject,
      sent_at,
      from_addrs,
      from_simple,
      to_addrs,
      reply_to_addrs,
      headers,
      body_content,
      body_html,
      body_text,
      body_text_as_html,
      label_ids,
      size_estimate
    FROM email.gmail_message
    WHERE gmail_id = ANY($1)
    ORDER BY ARRAY_POSITION($1, gmail_id)`,
    [gmailIds]
  );

  return result.rows;
}

/**
 * Load all short test samples (< 500 chars).
 */
export async function loadShortEmails(pool: Pool): Promise<GmailMessage[]> {
  return loadEmails(pool, TEST_SAMPLES.short);
}

/**
 * Load all medium test samples (500-2000 chars).
 */
export async function loadMediumEmails(pool: Pool): Promise<GmailMessage[]> {
  return loadEmails(pool, TEST_SAMPLES.medium);
}

/**
 * Load all long test samples (> 2000 chars).
 */
export async function loadLongEmails(pool: Pool): Promise<GmailMessage[]> {
  return loadEmails(pool, TEST_SAMPLES.long);
}

/**
 * Load rule-based test batch (short + medium emails).
 * Expected: All emails should use rule-based path without AI routing.
 */
export async function loadRuleBasedBatch(pool: Pool): Promise<GmailMessage[]> {
  return loadEmails(pool, [...TEST_SAMPLES.short, ...TEST_SAMPLES.medium]);
}

/**
 * Load mixed test batch (all complexity levels).
 * Expected: Mix of rule-based and AI-routed classifications.
 */
export async function loadMixedBatch(pool: Pool): Promise<GmailMessage[]> {
  return loadEmails(pool, [
    ...TEST_SAMPLES.short,
    ...TEST_SAMPLES.medium,
    ...TEST_SAMPLES.long,
  ]);
}

/**
 * Load AI candidate batch (long emails only).
 * Expected: Some may trigger AI routing depending on confidence scores.
 */
export async function loadAICandidateBatch(pool: Pool): Promise<GmailMessage[]> {
  return loadEmails(pool, TEST_SAMPLES.long);
}

/**
 * Create a database connection pool for testing.
 * Caller is responsible for calling pool.end() when done.
 */
export function createTestPool(): Pool {
  return new Pool(getDbConfig());
}

