#!/usr/bin/env node
/**
 * Classification Performance Profiling Script (T073)
 *
 * Profiles classification pipeline performance using deterministic test datasets.
 * Measures per-stage timing, AI vs non-AI path performance, and identifies bottlenecks.
 *
 * Usage:
 *   npm run profile:classification              # Run all batches
 *   npm run profile:classification -- --batch rule-based  # Run specific batch
 *   npm run profile:classification -- --email 19928d6e49543f03  # Profile single email
 *
 * Output:
 *   - Console: Performance summary with per-stage timings
 *   - File: ./performance-analysis.md (detailed analysis with bottleneck identification)
 */

import { Pool } from 'pg';
import { ClassificationPipeline } from '../pipeline/classification-pipeline';
import { loadConfigurationFromFile } from '../config/config-loader';
import { EmailMessage } from '../types/email-message';
import { ClassificationResult } from '../types/classification-result';
import * as path from 'path';
import * as fs from 'fs';

// Test data loader from email-processor package
// Note: We'll need to create a copy in classification-engine or import from email-processor
interface GmailMessage {
  gmail_id: string;
  gmail_thread_id: string;
  subject: string | null;
  sent_at: Date | null;
  from_addrs: any;
  from_simple: any;
  to_addrs: any;
  reply_to_addrs: any | null;
  headers: any;
  body_content: string | null;
  body_html: string | null;
  body_text: string | null;
  body_text_as_html: string | null;
  label_ids: string[];
  size_estimate: number | null;
}

const TEST_SAMPLES = {
  short: [
    '19928d6e49543f03', // hawaiian shirt (1 char)
    '19923533a9049beb', // todos (42 chars)
    '199d3e4371fc8b53', // stuff to talk about (139 chars)
  ],
  medium: [
    '1988896ac502a7f4', // direct deposit (1465 chars)
    '19892a6cf91ee002', // tracked flight (1482 chars)
    '19906810d60cd26d', // crypto portfolio (1301 chars)
  ],
  long: [
    '1997666491effefc', // lab results (2908 chars)
    '1987f215352815b2', // github ceo claude (9987 chars)
    '1990fc8fe96cb6bb', // openai anthropic mistral (10542 chars)
  ],
};

interface TimingStats {
  min: number;
  max: number;
  avg: number;
  p50: number;
  p95: number;
  count: number;
  total: number;
}

interface ProfilingResults {
  totalEmails: number;
  ruleBasedEmails: number;
  aiRoutedEmails: number;
  stageTimings: Record<string, TimingStats>;
  pathTimings: {
    ruleBased: TimingStats;
    aiRouted: TimingStats;
  };
  bottlenecks: Array<{
    stage: string;
    avgMs: number;
    percentOfTotal: number;
  }>;
}

/**
 * Database connection helper
 */
function createPool(): Pool {
  return new Pool({
    host: process.env.POSTGRES_HOST || 'localhost',
    port: parseInt(process.env.POSTGRES_PORT || '5432', 10),
    database: process.env.PROJECT_DB_NAME || 'gmail_automation',
    user: process.env.PROJECT_DB_USER || 'gmail_app_user',
    password: process.env.PROJECT_DB_PASS,
  });
}

/**
 * Load emails from database by IDs
 */
async function loadEmails(pool: Pool, gmailIds: readonly string[]): Promise<GmailMessage[]> {
  const result = await pool.query(
    `SELECT
      gmail_id,
      gmail_thread_id,
      subject,
      sent_at,
      from_addrs,
      from_simple,
      to_addrs,
      reply_to_addrs,
      headers,
      body_content,
      body_html,
      body_text,
      body_text_as_html,
      label_ids,
      size_estimate
    FROM email.gmail_message
    WHERE gmail_id = ANY($1)
    ORDER BY ARRAY_POSITION($1, gmail_id)`,
    [gmailIds]
  );
  return result.rows;
}

/**
 * Convert GmailMessage to EmailMessage format
 */
function convertToEmailMessage(msg: GmailMessage): EmailMessage {
  return {
    id: msg.gmail_id,
    threadId: msg.gmail_thread_id,
    subject: msg.subject || '',
    from: msg.from_simple?.address || '',
    fromName: msg.from_simple?.name || '',
    to: msg.to_addrs?.value?.map((v: any) => v.address) || [],
    body: msg.body_text || msg.body_content || '',
    bodyHtml: msg.body_html || null,
    headers: msg.headers || {},
    receivedDate: msg.sent_at ? new Date(msg.sent_at) : new Date(),
    labels: msg.label_ids || [],
  };
}

/**
 * Calculate timing statistics from array of measurements
 */
function calculateStats(timings: number[]): TimingStats {
  if (timings.length === 0) {
    return { min: 0, max: 0, avg: 0, p50: 0, p95: 0, count: 0, total: 0 };
  }

  const sorted = [...timings].sort((a, b) => a - b);
  const sum = timings.reduce((acc, val) => acc + val, 0);

  return {
    min: sorted[0],
    max: sorted[sorted.length - 1],
    avg: sum / timings.length,
    p50: sorted[Math.floor(sorted.length * 0.5)],
    p95: sorted[Math.floor(sorted.length * 0.95)],
    count: timings.length,
    total: sum,
  };
}

/**
 * Analyze profiling results and identify bottlenecks
 */
function analyzeResults(results: ClassificationResult[]): ProfilingResults {
  const stageTimingsData: Record<string, number[]> = {};
  const ruleBasedTimings: number[] = [];
  const aiRoutedTimings: number[] = [];

  let ruleBasedCount = 0;
  let aiRoutedCount = 0;

  // Collect all timing data
  for (const result of results) {
    const totalTime = result.processingDurationMs;
    const isAiRouted = result.aiRoutingUsed;

    if (isAiRouted) {
      aiRoutedTimings.push(totalTime);
      aiRoutedCount++;
    } else {
      ruleBasedTimings.push(totalTime);
      ruleBasedCount++;
    }

    // Collect per-stage timings
    for (const [stage, timing] of Object.entries(result.explainabilityTrace.stageTimings)) {
      if (!stageTimingsData[stage]) {
        stageTimingsData[stage] = [];
      }
      stageTimingsData[stage].push(timing);
    }
  }

  // Calculate stats for each stage
  const stageTimings: Record<string, TimingStats> = {};
  let totalAvgTime = 0;

  for (const [stage, timings] of Object.entries(stageTimingsData)) {
    const stats = calculateStats(timings);
    stageTimings[stage] = stats;
    totalAvgTime += stats.avg;
  }

  // Identify bottlenecks (stages taking > 5% of total time)
  const bottlenecks = Object.entries(stageTimings)
    .map(([stage, stats]) => ({
      stage,
      avgMs: stats.avg,
      percentOfTotal: totalAvgTime > 0 ? (stats.avg / totalAvgTime) * 100 : 0,
    }))
    .filter((b) => b.percentOfTotal > 5)
    .sort((a, b) => b.avgMs - a.avgMs);

  return {
    totalEmails: results.length,
    ruleBasedEmails: ruleBasedCount,
    aiRoutedEmails: aiRoutedCount,
    stageTimings,
    pathTimings: {
      ruleBased: calculateStats(ruleBasedTimings),
      aiRouted: calculateStats(aiRoutedTimings),
    },
    bottlenecks,
  };
}

/**
 * Format profiling results as markdown report
 */
function formatMarkdownReport(profiling: ProfilingResults): string {
  const lines: string[] = [];

  lines.push('# Classification Performance Analysis (T073)');
  lines.push('');
  lines.push(`**Date**: ${new Date().toISOString()}`);
  lines.push(`**Total Emails Profiled**: ${profiling.totalEmails}`);
  lines.push('');

  // Path breakdown
  lines.push('## Classification Path Breakdown');
  lines.push('');
  lines.push(`- **Rule-based path**: ${profiling.ruleBasedEmails} emails (${((profiling.ruleBasedEmails / profiling.totalEmails) * 100).toFixed(1)}%)`);
  lines.push(`- **AI-routed path**: ${profiling.aiRoutedEmails} emails (${((profiling.aiRoutedEmails / profiling.totalEmails) * 100).toFixed(1)}%)`);
  lines.push('');

  // Path performance
  lines.push('## Path-Specific Performance');
  lines.push('');
  lines.push('### Rule-Based Path (Stages 1-7, 9-10)');
  lines.push('');
  const rb = profiling.pathTimings.ruleBased;
  lines.push(`- **Target**: < 1000ms per email`);
  lines.push(`- **Average**: ${rb.avg.toFixed(2)}ms`);
  lines.push(`- **P50**: ${rb.p50.toFixed(2)}ms`);
  lines.push(`- **P95**: ${rb.p95.toFixed(2)}ms`);
  lines.push(`- **Min/Max**: ${rb.min.toFixed(2)}ms / ${rb.max.toFixed(2)}ms`);
  lines.push(`- **Status**: ${rb.avg < 1000 ? '✅ PASSING' : '❌ FAILING'}`);
  lines.push('');

  lines.push('### AI-Routed Path (Stages 1-10 with AI)');
  lines.push('');
  const ai = profiling.pathTimings.aiRouted;
  if (ai.count > 0) {
    lines.push(`- **Target**: < 10000ms per email`);
    lines.push(`- **Average**: ${ai.avg.toFixed(2)}ms`);
    lines.push(`- **P50**: ${ai.p50.toFixed(2)}ms`);
    lines.push(`- **P95**: ${ai.p95.toFixed(2)}ms`);
    lines.push(`- **Min/Max**: ${ai.min.toFixed(2)}ms / ${ai.max.toFixed(2)}ms`);
    lines.push(`- **Status**: ${ai.avg < 10000 ? '✅ PASSING' : '❌ FAILING'}`);
  } else {
    lines.push('- **No AI-routed emails in this batch**');
  }
  lines.push('');

  // Per-stage timings
  lines.push('## Per-Stage Timing Breakdown');
  lines.push('');
  lines.push('| Stage | Min (ms) | Avg (ms) | P50 (ms) | P95 (ms) | Max (ms) | Count |');
  lines.push('|-------|----------|----------|----------|----------|----------|-------|');

  for (const [stage, stats] of Object.entries(profiling.stageTimings)) {
    lines.push(
      `| ${stage} | ${stats.min.toFixed(2)} | ${stats.avg.toFixed(2)} | ${stats.p50.toFixed(2)} | ${stats.p95.toFixed(2)} | ${stats.max.toFixed(2)} | ${stats.count} |`
    );
  }
  lines.push('');

  // Bottlenecks
  lines.push('## Identified Bottlenecks (> 5% of total time)');
  lines.push('');

  if (profiling.bottlenecks.length === 0) {
    lines.push('**No significant bottlenecks identified** (all stages < 5% of total time)');
  } else {
    lines.push('| Rank | Stage | Avg Time (ms) | % of Total |');
    lines.push('|------|-------|---------------|------------|');

    profiling.bottlenecks.forEach((bottleneck, index) => {
      lines.push(`| ${index + 1} | ${bottleneck.stage} | ${bottleneck.avgMs.toFixed(2)} | ${bottleneck.percentOfTotal.toFixed(1)}% |`);
    });
  }
  lines.push('');

  // Recommendations
  lines.push('## Optimization Recommendations');
  lines.push('');

  if (profiling.bottlenecks.length > 0) {
    lines.push('Focus optimization efforts on the following stages (in priority order):');
    lines.push('');
    profiling.bottlenecks.forEach((bottleneck, index) => {
      lines.push(`${index + 1}. **${bottleneck.stage}** - ${bottleneck.avgMs.toFixed(2)}ms average (${bottleneck.percentOfTotal.toFixed(1)}% of total time)`);
    });
  } else {
    lines.push('- No major bottlenecks identified');
    lines.push('- All stages performing efficiently (< 5% of total time each)');
  }
  lines.push('');

  return lines.join('\n');
}

/**
 * Main profiling function
 */
async function main() {
  const args = process.argv.slice(2);
  const batchType = args.includes('--batch') ? args[args.indexOf('--batch') + 1] : 'all';
  const emailId = args.includes('--email') ? args[args.indexOf('--email') + 1] : null;

  console.log('🔍 Classification Performance Profiling (T073)\n');

  // Load configuration
  const configPath = path.resolve(__dirname, '../../../../../config/categories.json');
  const config = await loadConfigurationFromFile(configPath);

  // Create pipeline
  const pipeline = new ClassificationPipeline(config);

  // Connect to database
  const pool = createPool();

  try {
    let emailIds: string[];
    let batchLabel: string;

    if (emailId) {
      emailIds = [emailId];
      batchLabel = `Single email: ${emailId}`;
    } else if (batchType === 'rule-based') {
      emailIds = [...TEST_SAMPLES.short, ...TEST_SAMPLES.medium];
      batchLabel = 'Rule-based batch (short + medium)';
    } else if (batchType === 'ai-candidates') {
      emailIds = TEST_SAMPLES.long;
      batchLabel = 'AI candidate batch (long emails)';
    } else if (batchType === 'mixed') {
      emailIds = [...TEST_SAMPLES.short, ...TEST_SAMPLES.medium, ...TEST_SAMPLES.long];
      batchLabel = 'Mixed batch (all complexity levels)';
    } else {
      // Default: all samples
      emailIds = [...TEST_SAMPLES.short, ...TEST_SAMPLES.medium, ...TEST_SAMPLES.long];
      batchLabel = 'All test samples';
    }

    console.log(`📊 Batch: ${batchLabel}`);
    console.log(`📧 Processing ${emailIds.length} emails...\n`);

    // Load emails
    const gmailMessages = await loadEmails(pool, emailIds);
    const emailMessages = gmailMessages.map(convertToEmailMessage);

    // Classify all emails
    const results: ClassificationResult[] = [];
    for (const email of emailMessages) {
      console.log(`  Classifying: ${email.id} - "${email.subject}"`);
      const result = await pipeline.classifyEmail(email);
      results.push(result);
    }

    console.log(`\n✅ Classified ${results.length} emails\n`);

    // Analyze results
    const profiling = analyzeResults(results);

    // Print summary to console
    console.log('📈 Performance Summary:\n');
    console.log(`Rule-based path: ${profiling.pathTimings.ruleBased.avg.toFixed(2)}ms avg (target: < 1000ms)`);
    if (profiling.aiRoutedEmails > 0) {
      console.log(`AI-routed path: ${profiling.pathTimings.aiRouted.avg.toFixed(2)}ms avg (target: < 10000ms)`);
    }

    if (profiling.bottlenecks.length > 0) {
      console.log('\n🚨 Top Bottlenecks:');
      profiling.bottlenecks.slice(0, 3).forEach((b, i) => {
        console.log(`  ${i + 1}. ${b.stage}: ${b.avgMs.toFixed(2)}ms (${b.percentOfTotal.toFixed(1)}%)`);
      });
    }

    // Write detailed report to file
    const reportPath = path.resolve(process.cwd(), 'performance-analysis.md');
    const report = formatMarkdownReport(profiling);
    fs.writeFileSync(reportPath, report, 'utf-8');

    console.log(`\n📝 Detailed report written to: ${reportPath}\n`);
  } finally {
    await pool.end();
  }
}

// Run profiling
main().catch((error) => {
  console.error('❌ Profiling failed:', error);
  process.exit(1);
});

