#!/usr/bin/env node
/**
 * One-time script to export test email samples from database to JSON files
 * Run: node export-samples.js
 */

const { Pool } = require('pg');
const fs = require('fs');
const path = require('path');

const TEST_SAMPLES = {
  short: [
    { id: '19928d6e49543f03', name: 'hawaiian-shirt' },
    { id: '19923533a9049beb', name: 'todos' },
    { id: '199d3e4371fc8b53', name: 'stuff-to-talk-about' },
  ],
  medium: [
    { id: '1988896ac502a7f4', name: 'direct-deposit' },
    { id: '19892a6cf91ee002', name: 'tracked-flight' },
    { id: '19906810d60cd26d', name: 'crypto-portfolio' },
  ],
  long: [
    { id: '1997666491effefc', name: 'lab-results' },
    { id: '1987f215352815b2', name: 'github-ceo-claude' },
    { id: '1990fc8fe96cb6bb', name: 'openai-anthropic-mistral' },
  ],
};

async function main() {
  const pool = new Pool({
    host: process.env.POSTGRES_HOST || 'localhost',
    port: parseInt(process.env.POSTGRES_PORT || '5432', 10),
    database: process.env.PROJECT_DB_NAME || 'gmail_automation',
    user: process.env.PROJECT_DB_USER || 'gmail_app_user',
    password: process.env.PROJECT_DB_PASS,
  });

  try {
    for (const [category, samples] of Object.entries(TEST_SAMPLES)) {
      const categoryDir = path.join(__dirname, category);
